    60→            ILogger<CreateCompanyCommandHandler> logger)
    61→        {
    62→            _companyRepository = companyRepository ?? throw new ArgumentNullException(nameof(companyRepository));
    63→            _unitOfWork = unitOfWork ?? throw new ArgumentNullException(nameof(unitOfWork));
    64→            _currencyConversion = currencyConversion ?? throw new ArgumentNullException(nameof(currencyConversion));
    65→            _logger = logger ?? throw new ArgumentNullException(nameof(logger));
