    67→
    68→        public async Task<CreateCompanyResult> Handle(
    69→            CreateCompanyCommand request,
    70→            CancellationToken cancellationToken)
    71→        {
    72→            // Step ‑1: Defensive checks ------------------------------------------------------
    73→            if (string.IsNullOrWhiteSpace(request.Name))
    74→                throw new ValidationException("Company name must be provided.");
    75→
    76→            if (request.InitialCapital < 10_000)
    77→                throw new ValidationException("Initial capital must be at least 10 000 in-game credits.");
    78→
    79→            if (!RegionInfo.CurrentRegion.TwoLetterISORegionName.Equals(
    80→                    request.CountryIsoCode, StringComparison.OrdinalIgnoreCase)
    81→                && request.CountryIsoCode.Length != 2)
    82→            {
    83→                throw new ValidationException("Country ISO code must be a valid two-letter ISO 3166-1 value.");
    84→            }
    85→
    86→            // Step 0: Ensure player does not already own a company with the same name ------
    87→            bool duplicateExists = await _companyRepository.ExistsAsync(
    88→                request.Name, request.RequestedByPlayerId, cancellationToken);
    89→
    90→            if (duplicateExists)
    91→                throw new BusinessRuleException($"A company named '{request.Name}' already exists for this player.");
    92→
    93→            // Step 1: Convert the initial capital into the internal accounting currency ----
    94→            // The game operates with "G-Credits" internally, but players can seed with local currencies.
    95→            Money seedCapital = await _currencyConversion.ConvertAsync(
    96→                new Money(request.InitialCapital, CurrencyCode.GCredits),  // assuming already in credits
    97→                cancellationToken);
    98→
    99→            // Step 2: Create the domain entity (aggregate root) -----------------------------
   100→            var company = Company.Create(
   101→                name: request.Name,
   102→                industry: request.Industry,
   103→                initialCapital: seedCapital,
   104→                regionIsoCode: request.CountryIsoCode,
   105→                foundedByPlayerId: request.RequestedByPlayerId);
   106→
   107→            // Step 3: Persist the aggregate through repository + commit ---------------------
   108→            await _companyRepository.AddAsync(company, cancellationToken);
   109→            await _unitOfWork.SaveChangesAsync(cancellationToken);
   110→
   111→            _logger.LogInformation(
   112→                "Player {PlayerId} created company {CompanyName} (Id: {CompanyId})",
   113→                request.RequestedByPlayerId,
   114→                company.Name,
   115→                company.Id);
   116→
   117→            // Step 4: Return DTO ------------------------------------------------------------
   118→            return new CreateCompanyResult(company.Id, company.CreatedAtUtc);
   119→        }
   120→    }
