    59→            _jsonOptions = jsonOptions ?? new JsonSerializerOptions
    60→            {
    61→                PropertyNamingPolicy        = JsonNamingPolicy.CamelCase,
    62→                DefaultIgnoreCondition      = System.Text.Json.Serialization.JsonIgnoreCondition.WhenWritingNull,
    63→                PropertyNameCaseInsensitive = true
    64→            };
