    89→        /// <inheritdoc />
    90→        public async Task<TResponse?> SendAsync<TResponse>(
    91→            ApiRequest request,
    92→            CancellationToken cancellationToken = default)
    93→        {
    94→            if (request is null) throw new ArgumentNullException(nameof(request));
    95→            ThrowIfDisposed();
    96→
    97→            if (!_connectivity.IsOnline)
    98→            {
    99→                await QueueOfflineAsync(request, cancellationToken).ConfigureAwait(false);
   100→                return default;
   101→            }
   102→
   103→            // Attach auth token just-in-time
   104→            await EnsureAuthorizationHeaderAsync(cancellationToken).ConfigureAwait(false);
   105→
   106→            using var httpRequest = BuildHttpRequestMessage(request);
   107→
   108→            HttpResponseMessage? response = null;
   109→            try
   110→            {
   111→                response = await _retryPolicy.ExecuteAsync(
   112→                    ct => _httpClient.SendAsync(httpRequest, HttpCompletionOption.ResponseHeadersRead, ct),
   113→                    cancellationToken).ConfigureAwait(false);
   114→
   115→                // If connectivity died mid request, store and bubble
   116→                if (!_connectivity.IsOnline)
   117→                {
   118→                    await QueueOfflineAsync(request, cancellationToken).ConfigureAwait(false);
   119→                    return default;
   120→                }
   121→
   122→                if (response.IsSuccessStatusCode)
   123→                {
   124→                    // Fast-path for void result
   125→                    if (typeof(TResponse) == typeof(VoidType))
   126→                        return default;
   127→
   128→                    // Read the JSON body
   129→                    var stream = await response.Content.ReadAsStreamAsync(cancellationToken).ConfigureAwait(false);
   130→
   131→                    var result = await JsonSerializer.DeserializeAsync<TResponse>(
   132→                        stream,
   133→                        _jsonOptions,
   134→                        cancellationToken).ConfigureAwait(false);
   135→
   136→                    return result;
   137→                }
   138→
   139→                // Unauthorized? Token might be expired – attempt refresh once.
   140→                if (response.StatusCode == HttpStatusCode.Unauthorized)
   141→                {
   142→                    _logger.LogInformation("401 Unauthorized received. Refreshing bearer token.");
   143→                    await _authProvider.RefreshTokenAsync(cancellationToken).ConfigureAwait(false);
   144→
   145→                    // Re-attach new token
   146→                    await EnsureAuthorizationHeaderAsync(cancellationToken).ConfigureAwait(false);
   147→
   148→                    response = await _httpClient.SendAsync(httpRequest, cancellationToken).ConfigureAwait(false);
   149→
   150→                    if (response.IsSuccessStatusCode)
   151→                    {
   152→                        return await response.Content.ReadFromJsonAsync<TResponse>(
   153→                            _jsonOptions,
   154→                            cancellationToken).ConfigureAwait(false);
   155→                    }
   156→                }
   157→
   158→                // Let caller decide how to handle API-level errors
   159→                string errorPayload = await response.Content.ReadAsStringAsync(cancellationToken).ConfigureAwait(false);
   160→                throw new ApiException(
   161→                    response.StatusCode,
   162→                    $"Request to {request.Endpoint} failed with code {(int)response.StatusCode} ({response.StatusCode}).",
   163→                    errorPayload);
   164→            }
   165→            finally
   166→            {
   167→                response?.Dispose();
   168→            }
   169→        }
