   171→        /// <inheritdoc />
   172→        public async Task FlushOfflineQueueAsync(CancellationToken cancellationToken = default)
   173→        {
   174→            ThrowIfDisposed();
   175→
   176→            if (!_connectivity.IsOnline)
   177→                return;
   178→
   179→            IReadOnlyCollection<ApiRequest> pending = await _offlineStore.ReadAllAsync(cancellationToken).ConfigureAwait(false);
   180→            if (pending.Count == 0)
   181→                return;
   182→
   183→            _logger.LogInformation("Flushing {Count} queued API requests.", pending.Count);
   184→
   185→            foreach (var req in pending)
   186→            {
   187→                try
   188→                {
   189→                    await SendAsync<VoidType>(req, cancellationToken).ConfigureAwait(false);
   190→                    await _offlineStore.RemoveAsync(req.Id, cancellationToken).ConfigureAwait(false);
   191→                }
   192→                catch (Exception ex) when (!ex.IsFatal())
   193→                {
   194→                    _logger.LogWarning(ex, "Failed to flush queued request {RequestId}. It will be retried later.", req.Id);
   195→                    // Do not throw; continue processing the remainder.
   196→                }
   197→            }
   198→        }
