   138→    public async Task<AuthenticatePlayerResponse> Handle(
   139→        AuthenticatePlayerCommand command,
   140→        CancellationToken cancellationToken)
   141→    {
   142→        // 1. Sanity validation -------------------------------------------------------------------
   143→        if (string.IsNullOrWhiteSpace(command.Email))
   144→            return AuthenticatePlayerResponse.Fail("Email must be provided.");
   145→
   146→        // 2. Attempt offline authentication if requested ----------------------------------------
   147→        if (command.OfflineModeRequested)
   148→        {
   149→            var cached = _offlineCache.TryGet(command.Email);
   150→            if (cached != null)
   151→            {
   152→                _analytics.TrackEvent(AnalyticsEvent.OfflineAuthGranted, command.Email);
   153→                return AuthenticatePlayerResponse.Offline(cached);
   154→            }
   155→
   156→            // If offline login was explicitly requested and no cache found, we *fail fast*
   157→            return AuthenticatePlayerResponse.Fail("Offline credentials not found.");
   158→        }
   159→
   160→        // 3. Fetch player aggregate from repository ---------------------------------------------
   161→        var player = await _playerRepository.GetByEmailAsync(command.Email, cancellationToken);
   162→        if (player is null)
   163→            return AuthenticatePlayerResponse.Fail("Player not found.");
   164→
   165→        // 4. Validate credentials ----------------------------------------------------------------
   166→        bool isCredentialValid = false;
   167→
   168→        // 4a. Password flow
   169→        if (!string.IsNullOrWhiteSpace(command.Password))
   170→        {
   171→            isCredentialValid = _passwordService.VerifyHashedPassword(
   172→                player.PasswordHash,
   173→                command.Password);
   174→        }
   175→
   176→        // 4b. Biometric flow (if password failed / not provided)
   177→        if (!isCredentialValid && !string.IsNullOrWhiteSpace(command.BiometricSignature))
   178→        {
   179→            isCredentialValid = await _biometricAuthService.ValidateAsync(
   180→                player.Id,
   181→                command.BiometricSignature,
   182→                cancellationToken);
   183→        }
   184→
   185→        if (!isCredentialValid)
   186→        {
   187→            _analytics.TrackEvent(AnalyticsEvent.AuthFailed, command.Email);
   188→            return AuthenticatePlayerResponse.Fail("Invalid credentials.");
   189→        }
   190→
   191→        // 5. Build JWT and persist refresh token -------------------------------------------------
   192→        var (jwt, expiresAt) = _tokenService.GenerateAccessToken(player);
   193→        player.RefreshToken = _tokenService.GenerateRefreshToken();
   194→        player.RefreshTokenExpiry = expiresAt.AddDays(7);
