    /// <summary>
    /// Switches the player to Hardcore Mode. Requires active connectivity.
    /// </summary>
    public void EnableHardcoreMode(IConnectivityService connectivity)
    {
        if (!connectivity.IsOnline)
            throw new InvalidOperationException(
                "Cannot enable Hardcore Mode without active connectivity.");

        GameMode = GameMode.Hardcore;
        Publish(new GameModeChangedEvent(Id, GameMode.Hardcore));
    }

    /// <summary>
    /// Returns to standard offline-first mode.
    /// </summary>
    public void DisableHardcoreMode()
    {
        GameMode = GameMode.Standard;
        Publish(new GameModeChangedEvent(Id, GameMode.Standard));
    }
}
